using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private bool _isTrained;
    private readonly Lock _lock = new();

    public bool IsTrained => _isTrained;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 0);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResult TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel", "PredictedLabel"));

        var model = pipeline.Fit(dataView);

        _mlContext.Model.Save(model, dataView.Schema, _modelPath);

        lock (_lock)
        {
            _predictionEngine = _mlContext.Model
                .CreatePredictionEngine<TicketData, TicketPrediction>(model);
            _isTrained = true;
        }

        // Evaluate using the training data (small dataset, no split needed)
        var predictions = model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var perClass = new List<PerClassMetric>();
        if (metrics.PerClassLogLoss is not null)
        {
            var classNames = new[] { "Billing", "General", "Technical" };
            for (int i = 0; i < classNames.Length && i < metrics.PerClassLogLoss.Count; i++)
            {
                perClass.Add(new PerClassMetric
                {
                    ClassName = classNames[i],
                    Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                    F1Score = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                              && i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? 2 * metrics.ConfusionMatrix.PerClassPrecision[i]
                              * metrics.ConfusionMatrix.PerClassRecall[i]
                              / (metrics.ConfusionMatrix.PerClassPrecision[i]
                                 + metrics.ConfusionMatrix.PerClassRecall[i] + 1e-15)
                        : 0
                });
            }
        }

        return new EvaluationResult
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = perClass.ToArray()
        };
    }

    public TicketPrediction Predict(PredictionRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null)
                throw new InvalidOperationException(
                    "Model has not been trained. POST to /api/model/train first.");

            return _predictionEngine.Predict(new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            });
        }
    }
}

