using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class PredictController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost]
    public IActionResult Predict([FromBody] PredictionRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) &&
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject or Description is required.");
        }

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        if (!classifier.IsTrained)
            return BadRequest("Model has not been trained. POST to /api/model/train first.");

        var prediction = classifier.Predict(request);

        return Ok(new
        {
            prediction.Category,
            Confidence = prediction.Score?.Max()
        });
    }
}

